class PrecedentInterceptor:
    """基于 facts 表的失败先例拦截。

    intercept(action, session_data) → PrecedentResult
    """

    def __init__(self, config: dict | None = None):
        self._config = config or {}
        self._match_cfg = config.get("matching", {}) if config else {}
        self._data = None  # 延迟加载

    @property
    def data(self):
        """延迟加载 facts 数据源。"""
        if self._data is None:
            from src.coach.data import TripleLayerGraph
            self._data = TripleLayerGraph(":memory:")
        return self._data
```

注意：data.py 的 facts 表 schema 不可修改。
TripleLayerGraph 的 __init__ 可能需要 session_id 参数。
